66	  it.todo("7 runes → 180 G premium (175 base + 5 fee)");
67	  it.todo("2 runes + 1 moonstone → 80 G premium (75 base, no block since different types)");
68	  it.todo("3 runes + 3 moonstones → 125 G premium (120 base, two separate blocks)");
69	
70	  // Item-specific modifiers (cursed, high enchantment)
71	  it.todo("cursed sword (enchantment 3) → curse surcharge 50%: 100 + 50 + 5 = 155 G");
