77	  it.todo("customer with 2 years → loyalty discount 20% applies");
78	  it.todo("customer with 0 years → no loyalty discount");
79	
80	  // Modifier scope on multi-item policies
81	  it.todo("cursed sword + plain amulet → curse applies to sword only: 100+60+50+5 = 215 G");
82	
83	  // First insurance surcharge
84	  it.todo("first insurance per item: +10% per item base premium");
85	
86	  // Follow-up contract discount
