88	
89	  // Rounding
90	  it.todo("premium 197.5 G → rounded up to 198 G (in MHPCO's favor)");
91	
92	  // Integration examples
93	  it.todo("newcomer with cursed sword (steel, enchantment 3): 0 years, first contract → premium 165 G");
94	  it.todo("long-standing customer's 2nd contract: cursed sword enchant 7, 3 years → premium 160 G");
95	
96	  // Claim: standard reimbursement
97	  it.todo("claim on plain sword (enchant 3), damage 500 G → payout 400 G");
98	  it.todo("claim on rune, damage 200 G → payout 100 G (no special clause)");
99	
100	  // Claim: enchantment threshold
101	  it.todo("claim on steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
102	
103	  // Claim: dragon material
104	  it.todo("claim on dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
105	  it.todo("claim on dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
106	  it.todo("claim on dragon sword, enchantment 8, damage 1000 G → payout 400 G (high-enchant clause applies)");
107	
108	  // Claim: deductible per damage event
109	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
110	
111	  // Claim: payout rounding (down)
112	  it.todo("payout 350.5 G → final payout 350 G (rounded down in MHPCO's favor)");
113	
114	  // Multiple items of same type
115	  it.todo("policy with 2 swords → insurance sum 2000, cap 4000; two damages each get own deductible");
116	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
117	
118	  // Cap exhaustion
119	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
120	  it.todo("cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
121	  it.todo("sword + 3 runes block → insurance sum 1750 (block affects premium only)");
122	  it.todo("sword 2 successive claims of 1500 each → first payout 1400 (cap 600 left), second payout 600 (cap 0)");
123	
124	  // Error cases
125	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error");
126	  it.todo("claim references item not in policy → CLI exits non-zero with stderr error");
127	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr error");
128	});
