1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const BLOCK_SIZE = 3;
7	const BLOCK_DISCOUNT = 15;
8	
9	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const TYPES_WITH_BLOCK_DISCOUNT = new Set(["rune"]);
18	
19	const countsByType = (items: Item[]): Record<string, number> =>
20	  items.reduce<Record<string, number>>(
21	    (counts, item) => ({ ...counts, [item.type]: (counts[item.type] ?? 0) + 1 }),
22	    {},
23	  );
24	
25	const baseForTypeGroup = (type: string, count: number): number => {
26	  const blockDiscount = TYPES_WITH_BLOCK_DISCOUNT.has(type) && count === BLOCK_SIZE ? BLOCK_DISCOUNT : 0;
27	  return count * BASE_PREMIUM_BY_TYPE[type] - blockDiscount;
28	};
29	
30	const quoteStep = (step: QuoteStep): { premium: number } => {
31	  const counts = countsByType(step.items);
32	  const itemsBase = Object.entries(counts).reduce(
33	    (sum, [type, count]) => sum + baseForTypeGroup(type, count),
34	    0,
35	  );
36	  return { premium: itemsBase + PROCESSING_FEE };
37	};
38	
39	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
40	  return { results: scenario.steps.map(quoteStep) };
41	};
